import React, { useEffect, useState } from 'react';
import { bookingService, resourceService } from '../services/api';
import { useNavigate } from 'react-router-dom';
import { CheckCircle, XCircle, Eye } from 'lucide-react';
import { useSearch } from '../context/SearchContext';
import { useAuth } from '../context/AuthContext';
import './Table.css';

export default function AdminBookingsPage() {
    const { user } = useAuth();
    const navigate = useNavigate();
    const [bookings, setBookings] = useState([]);
    const [resources, setResources] = useState([]);
    const [loading, setLoading] = useState(true);

    // Filters
    const [statusFilter, setStatusFilter] = useState('');
    const [resourceFilter, setResourceFilter] = useState('');
    const [startDate, setStartDate] = useState('');
    const [endDate, setEndDate] = useState('');
    const { searchQuery } = useSearch();

    const fetchBookings = async () => {
        setLoading(true);
        try {
            const params = {};
            if (statusFilter) params.status = statusFilter;
            if (resourceFilter) params.resourceId = resourceFilter;
            if (startDate) params.startDate = startDate;
            if (endDate) params.endDate = endDate;

            const res = await bookingService.getAllBookings(params);
            setBookings(res.data);
        } catch (err) {
            console.error(err);
        } finally {
            setLoading(false);
        }
    };

    useEffect(() => {
        resourceService.getResources().then(res => setResources(res.data)).catch(console.error);
    }, []);

    useEffect(() => {
        fetchBookings();
    }, [statusFilter, resourceFilter, startDate, endDate, user?.role]);

    const handleApprove = async (id) => {
        if (!window.confirm('Approve this booking?')) return;
        try {
            await bookingService.updateStatus(id, 'APPROVED');
            fetchBookings();
        } catch (err) {
            alert('Failed to approve booking.');
        }
    };

    const handleReject = async (id) => {
        const reason = window.prompt("Please provide a reason for rejection:");
        if (reason === null) return; // User cancelled
        if (!reason.trim()) return alert("Rejection reason is required.");

        try {
            await bookingService.updateStatus(id, 'REJECTED', reason);
            fetchBookings();
        } catch (err) {
            alert('Failed to reject booking.');
        }
    };

    return (
        <div className="page-container">
            <h1 className="page-title">Manage Bookings</h1>

            <div className="glass-panel filter-bar">
                <div className="filter-group">
                    <label>Status</label>
                    <select value={statusFilter} onChange={e => setStatusFilter(e.target.value)} className="form-input">
                        <option value="">All Statuses</option>
                        <option value="PENDING">Pending</option>
                        <option value="APPROVED">Approved</option>
                        <option value="REJECTED">Rejected</option>
                        <option value="CANCELLED">Cancelled</option>
                        <option value="NO_SHOW">No Show</option>
                    </select>
                </div>

                <div className="filter-group">
                    <label>Resource</label>
                    <select value={resourceFilter} onChange={e => setResourceFilter(e.target.value)} className="form-input">
                        <option value="">All Resources</option>
                        {resources.map(r => (
                            <option key={r.id} value={r.id}>{r.name}</option>
                        ))}
                    </select>
                </div>

                <div className="filter-group">
                    <label>From Date</label>
                    <input type="date" value={startDate} onChange={e => setStartDate(e.target.value)} className="form-input"/>
                </div>

                <div className="filter-group">
                    <label>To Date</label>
                    <input type="date" value={endDate} onChange={e => setEndDate(e.target.value)} className="form-input"/>
                </div>
            </div>

            <div className="glass-panel table-container">
                {loading ? (
                    <div className="loader">Loading Bookings...</div>
                ) : (
                    <table className="data-table">
                        <thead>
                            <tr>
                                <th>User</th>
                                <th>Resource</th>
                                <th>Date & Time</th>
                                <th>Purpose</th>
                                <th>Status</th>
                                <th>Actions</th>
                            </tr>
                        </thead>
                        <tbody>
                            {(() => {
                                const filteredBookings = bookings.filter(b => {
                                    const q = searchQuery.toLowerCase();
                                    return !q || 
                                        (b.purpose && b.purpose.toLowerCase().includes(q)) || 
                                        (b.userName && b.userName.toLowerCase().includes(q)) ||
                                        (b.userEmail && b.userEmail.toLowerCase().includes(q)) ||
                                        (b.resourceId && b.resourceId.toLowerCase().includes(q));
                                });
                                return (
                                    <>
                                        {filteredBookings.map(booking => (
                                <tr key={booking.id}>
                                    <td>
                                        <div className="user-cell">
                                            <strong>{booking.userName}</strong>
                                            <span className="text-muted">{booking.userEmail}</span>
                                        </div>
                                    </td>
                                    <td>{booking.resourceId}</td>
                                    <td>
                                        <div className="time-cell">
                                            <span>{booking.date}</span>
                                            <span className="text-muted">{booking.startTime} - {booking.endTime}</span>
                                        </div>
                                    </td>
                                    <td className="purpose-cell" title={booking.purpose}>{booking.purpose}</td>
                                    <td>
                                        <span className={`badge badge-${booking.status.toLowerCase()}`}>
                                            {booking.status}
                                        </span>
                                    </td>
                                    <td>
                                        <div className="action-buttons">
                                            <button 
                                                className="btn btn-secondary btn-icon"
                                                onClick={() => navigate(`/bookings/${booking.id}`)}
                                                title="View Details"
                                            >
                                                <Eye size={16}/>
                                            </button>

                                            {booking.status === 'PENDING' && (
                                                <>
                                                    <button 
                                                        className="btn btn-primary btn-icon"
                                                        onClick={() => handleApprove(booking.id)}
                                                        title="Approve"
                                                    >
                                                        <CheckCircle size={16} />
                                                    </button>
                                                    <button 
                                                        className="btn btn-danger btn-icon"
                                                        onClick={() => handleReject(booking.id)}
                                                        title="Reject"
                                                    >
                                                        <XCircle size={16} />
                                                    </button>
                                                </>
                                            )}
                                            </div>
                                        </td>
                                    </tr>
                                ))}

                                {filteredBookings.length === 0 && (
                                    <tr>
                                        <td colSpan="6" className="text-center py-4">No bookings found.</td>
                                    </tr>
                                )}
                                    </>
                                );
                            })()}
                        </tbody>
                    </table>
                )}
            </div>
        </div>
    );
}

import React, { useEffect, useState } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { bookingService } from '../services/api';
import { useAuth } from '../context/AuthContext';
import QRCodeModal from '../components/QRCodeModal';
import { Calendar, Clock, MapPin, User, FileText, CheckCircle, XCircle, ArrowLeft } from 'lucide-react';
import './Detail.css';

export default function BookingDetailPage() {
    const { id } = useParams();
    const navigate = useNavigate();
    const { user } = useAuth();

    const [booking, setBooking] = useState(null);
    const [loading, setLoading] = useState(true);
    const [error, setError] = useState(null);
    const [showQR, setShowQR] = useState(false);

    const fetchBooking = async () => {
        try {
            const res = await bookingService.getBookingById(id);
            setBooking(res.data);
        } catch (err) {
            setError('Booking not found or you don\'t have permission to view it.');
        } finally {
            setLoading(false);
        }
    };

    useEffect(() => {
        fetchBooking();
    }, [id]);

    const handleApprove = async () => {
        if (!window.confirm('Approve this booking?')) return;
        try {
            await bookingService.updateStatus(id, 'APPROVED');
            fetchBooking();
        } catch (err) {
            alert('Failed to approve booking.');
        }
    };

    const handleReject = async () => {
        const reason = window.prompt("Please provide a reason for rejection:");
        if (reason === null) return; 
        if (!reason.trim()) return alert("Rejection reason is required.");

        try {
            await bookingService.updateStatus(id, 'REJECTED', reason);
            fetchBooking();
        } catch (err) {
            alert('Failed to reject booking.');
        }
    };

    const handleCancel = async () => {
        if (!window.confirm('Are you sure you want to cancel this booking?')) return;
        try {
            await bookingService.cancelBooking(id);
            fetchBooking();
        } catch (err) {
            alert('Failed to cancel booking.');
        }
    };

    if (loading) return <div className="loader">Loading Details...</div>;
    if (error) return <div className="page-container"><div className="alert alert-danger">{error}</div></div>;
    if (!booking) return null;

    const isAdmin = user?.role === 'ADMIN';
    const isOwner = user?.id === booking.userId;

    return (
        <div className="page-container">
            <button className="btn btn-secondary mb-4" onClick={() => navigate(-1)}>
                <ArrowLeft size={16} /> Back
            </button>

            <div className="detail-layout">
                <div className="glass-panel detail-main">
                    <div className="detail-header">
                        <div>
                            <h1 className="detail-title">{booking.purpose}</h1>
                            <span className="text-muted">Booking Reference: {booking.id}</span>
                        </div>
                        <span className={`badge badge-${booking.status.toLowerCase()}`}>
                            {booking.status}
                        </span>
                    </div>

                    <div className="detail-grid">
                        <div className="detail-item">
                            <MapPin size={20} className="detail-icon" />
                            <div>
                                <label>Resource</label>
                                <p>{booking.resourceId}</p>
                            </div>
                        </div>

                        <div className="detail-item">
                            <Calendar size={20} className="detail-icon" />
                            <div>
                                <label>Date</label>
                                <p>{booking.date}</p>
                            </div>
                        </div>

                        <div className="detail-item">
                            <Clock size={20} className="detail-icon" />
                            <div>
                                <label>Time Box</label>
                                <p>{booking.startTime} - {booking.endTime}</p>
                            </div>
                        </div>

                        <div className="detail-item">
                            <User size={20} className="detail-icon" />
                            <div>
                                <label>Requested By</label>
                                <p>{booking.userName} ({booking.userEmail})</p>
                                <p className="text-muted">ID: {booking.userId}</p>
                            </div>
                        </div>

                        <div className="detail-item">
                            <User size={20} className="detail-icon" />
                            <div>
                                <label>Attendees</label>
                                <p>{booking.expectedAttendees} expected</p>
                            </div>
                        </div>
                    </div>

                    {booking.rejectionReason && (
                        <div className="alert alert-danger mt-4">
                            <strong>Rejection Reason:</strong> {booking.rejectionReason}
                        </div>
                    )}
                </div>

                <div className="glass-panel detail-actions">
                    <h3>Actions</h3>

                    <div className="action-stack">
                        {isAdmin && booking.status === 'PENDING' && (
                            <>
                                <button className="btn btn-primary" onClick={handleApprove}>
                                    <CheckCircle size={16}/> Approve Booking
                                </button>
                                <button className="btn btn-danger" onClick={handleReject}>
                                    <XCircle size={16}/> Reject Booking
                                </button>
                            </>
                        )}

                        {isOwner && (booking.status === 'PENDING' || booking.status === 'APPROVED') && (
                            <button className="btn btn-danger" onClick={handleCancel}>
                                <XCircle size={16}/> Cancel Booking
                            </button>
                        )}

                        {booking.status === 'APPROVED' && (isAdmin || isOwner) && (
                            <button className="btn btn-secondary" onClick={() => setShowQR(true)}>
                                Show Check-in QR
                            </button>
                        )}

                        {!((isAdmin && booking.status === 'PENDING') || 
                           (isOwner && (booking.status === 'PENDING' || booking.status === 'APPROVED')) || 
                           booking.status === 'APPROVED') && (
                            <p className="text-muted text-center pt-2">No actions available for this state.</p>
                        )}
                    </div>
                </div>
            </div>

            {showQR && (
                <QRCodeModal 
                    token={booking.qrCodeToken} 
                    booking={booking}
                    onClose={() => setShowQR(false)} 
                />
            )}
        </div>
    );
}

